arguments.command:
perl -e '
use strict;
my $json = do { local $/; open(my $f, "<", "/app/answers.json") or die; <$f> };
# Simple JSON key check
my @keys = ($json =~ /"(\w+)"\s*:/g);
print "Keys found: ", join(", ", @keys), "\n";
my $has_rec = $json =~ /"recommendation"/ ? 1 : 0;
my $has_cls = $json =~ /"classification"/ ? 1 : 0;
my $has_imp = $json =~ /"implication"/ ? 1 : 0;
print "recommendation: $has_rec, classification: $has_cls, implication: $has_imp\n";
print "File size: ", length($json), " bytes\n";
print "JSON appears valid\n" if $has_rec && $has_cls && $has_imp;
'

